import os, json, requests, jwt, uuid, hashlib, urllib.parse
from dotenv import load_dotenv
load_dotenv\(\)
access_key = os.getenv\('UPBIT_ACCESS_KEY'\)
secret_key = os.getenv\('UPBIT_SECRET_KEY'\)

def get_orders\(state='done', page=1\):
    query = {'state': state, 'page': str\(page\), 'limit': '100', 'order_by': 'desc'}
    qs = urllib.parse.urlencode\(query\)
    m = hashlib.sha512\(\); m.update\(qs.encode\(\)\)
    payload = {'access_key': access_key, 'nonce': str\(uuid.uuid4\(\)\), 'query_hash': m.hexdigest\(\), 'query_hash_alg': 'SHA512'}
    token = jwt.encode\(payload, secret_key\)
    res = requests.get\('https://api.upbit.com/v1/orders', params=query, headers={'Authorization': f'Bearer {token}'}\)
    return res.json\(\)

orders = get_orders\(page=1\)
# side 분포 확인
sides = {}
for o in orders:
    if o['created_at'] >= '2026-04-03':
        sides[o['side']] = sides.get\(o['side'], 0\) + 1
print\(f'side 분포: {sides}'\)

# bid\(매수\) 주문 있는지 확인
bids = [o for o in orders if o['side'] == 'bid' and o['created_at'] >= '2026-04-03']
print\(f'매수\(bid\) 주문: {len\(bids\)}건'\)
if bids:
    print\(json.dumps\(bids[0], indent=2, ensure_ascii=False\)\)

# ord_type 분포
types = {}
for o in orders:
    if o['created_at'] >= '2026-04-03':
        types[o['ord_type']] = types.get\(o['ord_type'], 0\) + 1
print\(f'주문유형: {types}'\)
